var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내드립니다. 부상장병의 가족 여러분은 B동 프론트 데스크를 방문해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>ご案内いたします。負傷兵のご家族の皆さまは、B棟のフロントデスクまでお越しください。</color>","ENG":"<color=#ffd34c>Attention please. Families of wounded soldiers should go to Building B's front desk.</color>","TWN":"<color=#ffd34c>醫院通知，請傷者的家人移動至櫃台。</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>173차 응급 환자 도착했습니다. 대기 인원들은 전원 응급실로…….</color>","JPN":"<color=#ffd34c>173次の救急患者が到着しました。待機中のスタッフは全員救急処置室へ……</color>","ENG":"<color=#ffd34c>The 173rd emergency patients have arrived. All personnel to the emergency room...</color>","TWN":"<color=#ffd34c>第173波急救患者已抵達，請相關人員移動至急診室……</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"어디보자……. 202호, 202호…….","JPN":"えーと……202号室、202号室……","ENG":"Let’s see here... Room 202... 202...","TWN":"我看看喔……202號，202號……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"아, 이 병실 맞아?","JPN":"あ、この病室で合ってるかな？","ENG":"Are you sure this is the right place?","TWN":"是這間病房嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그래. 여기가 맞다.","JPN":"ああ、ここみたいだ。","ENG":"Yes. I’m sure.","TWN":"沒錯，就是這間。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"큰 오빠한테 애가 있었다니 의외네……. 장례식 치를 때도 몰랐는데.","JPN":"兄さんに子どもがいたなんて意外ね……\\n葬式の時にも来なかったみたいだし。","ENG":"I didn’t know big brother had a kid... I wasn’t even aware of it during the funeral.","TWN":"沒想到大哥竟然有孩子……之前在葬禮上也沒聽說。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"아버지가 예전에 큰 오빠네는 불임 판정 받았다고 하지 않았어?","JPN":"父さんが以前、兄さんのところは不妊だって言ってなかったっけ？","ENG":"Didn't Father say something about him being sterile?","TWN":"爸之前不是說大哥是不孕症嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그 인간 말을 곧이곧대로 믿지 마라. 그러니 아랫사람들에게 호구 소리 듣지.","JPN":"あの人が言ったことを素直に信じるな。だから目下の人間にも舐められるんだ。","ENG":"Don’t trust what that old geezer says. That’s why people call you gullible.","TWN":"那個人說的話你不用當真，你就是這樣才會被底下的人耍。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"신경 꺼. 내 일이거든.","JPN":"別にいいでしょ。余計なお世話よ。","ENG":"Whatever. That’s my business, not yours.","TWN":"不用你管，這不關你的事！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"흥. 뭐, 모르지. 아버지가 또 어디 첩에게서 덜컥 낳고 떠맡긴 걸지도.","JPN":"フン。まあ、親父がどっかの妾に産ませて、押し付けられたのかもな。","ENG":"Hmph. Who knows? Maybe Father got himself another wife and had another child with her.","TWN":"哼，誰知道，說不定是爸又跟哪個小三生的，然後叫大哥幫他養。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"내 앞에서 그딴 소리가 나와? 저질이야, 진짜.","JPN":"私の前でそんなこと言うわけ？　最低よ、本当に。","ENG":"You’re seriously saying that to my face? Unbelievable.","TWN":"你在我面前提什麼小三？有夠低級的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"저질이기로는 너만 하겠냐. 체스 도박 한 판에 건물 한 채씩 날려 먹는 주제에.","JPN":"最低なのはお前だろう。賭けチェスに興じるたびに、ビルを一棟吹っ飛ばすくせに。","ENG":"Not as much as you. You’re the one who lost an entire house on one chess gambling match.","TWN":"你以為只有你能低級嗎？是誰賭一局西洋棋，就把一棟房子輸掉的？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"아무리 생각해도 형님은 널 너무 오냐오냐 받아 줬어.","JPN":"どう考えても兄貴はお前に甘すぎだった。","ENG":"He’s always had a soft spot for you, for some reason...","TWN":"我看大哥就是太寵你了啦！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"내 욕은 해도 큰 오빠 욕은 하지 마. 다음에 이겨서 두 채로 받으면 되는 걸 가지고.","JPN":"私のことはいいけど、兄さんのことは悪く言わないでよ。\\n次の賭けで勝って、二棟分取り返せばいいでしょ。","ENG":"Talk trash about me all you want, but not to my big brother. Plus, I’ll double down and recover my losses next time.","TWN":"喂，你罵我就好，不要扯到大哥身上！我下次贏兩棟房子回來不就好了！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"……오빠, 막 입국해서 그러는데 큰 오빠네는 연구소 사고로 죽은 거 아니었어?","JPN":"……こっちに来たばかりでまだ状況がわからないけど、\\n兄さん一家って研究所の事故で死んだんじゃなかったっけ。","ENG":"Um...I just came back from overseas so... I thought his family died because of a lab accident?","TWN":"……哥，我才剛回來不久不是很清楚，大哥一家不是在研究室意外中喪生了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그래. 요즘 같은 난리통에도 대문짝만 하게 보도됐지.","JPN":"ああ、事件ばかりのこんなご時世でも、大々的に報道されたな。","ENG":"Yes. That’s how it was reported on the front page of the newspapers.","TWN":"沒錯，雖然最近世道很亂，但媒體還是有大篇幅的報導。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"그런데 쟤는 왜 상처 하나 없이 멀쩡한 건데?","JPN":"なのに、なんであの子は傷ひとつないの？","ENG":"But I don’t see any signs of trauma anywhere on her.","TWN":"那她為什麼毫髮無傷？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"궁금하면 직접 물어 봐. 난 관심없다.","JPN":"気になるなら自分で聞けよ。俺は興味ないから。","ENG":"Go ask about it yourself, if you’re that curious. I don’t care.","TWN":"想知道你自己問她吧，我沒興趣知道。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"으음…… 그러니까…… 안녕?","JPN":"うーん……そうね……こんにちは。","ENG":"So... Um... Hello?","TWN":"呃……那個……哈囉？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"……안녕하세요.","JPN":"……こんにちは。","ENG":"Hello...","TWN":"……你好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"갑작스럽겠지만…… 우린 네 고모랑 삼촌이란다. 이 과일은 병문안 선물.","JPN":"突然だけど……私たちはあなたの叔母と叔父よ。これはお見舞いの果物。","ENG":"I know it’s sudden, but we’re your aunt and uncle. Here’s some fruit I brought over for you.","TWN":"雖然有點突然……我們是你的姑姑和叔叔，這個水果是要給你吃的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"……고맙습니다. 잘 먹을게요, 고모님.","JPN":"……ありがとうございます。いただきます、叔母様。","ENG":"Thank you... You're very kind, Auntie.","TWN":"……謝謝姑姑的水果。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"예의가 참 바르네. 그런데 너, 혹시 이름이…….","JPN":"あら、礼儀正しい子ね。あの、あなたのお名前は……？","ENG":"Aren’t you a sweetheart. Oh, your name is...?","TWN":"好有禮貌喔，你叫什麼名字……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"지아예요. 신지아. 할아버님께서 지어 주셨어요.","JPN":"ユイです、ヒメノ・ユイ。お祖父様がこの名前をつけてくださいました。","ENG":"Jia. Shin Jia. Grandfather named me.","TWN":"我叫沈佳，是爺爺替我取的名字。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"아, 그렇구나. 참 좋은 이름이네.","JPN":"ああ、そうなのね。良い名前じゃない。","ENG":"I see. What a lovely name.","TWN":"原來是這樣，這個名字很好聽喔～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"뭐라고 말 좀 해 봐, 오빠.","JPN":"ちょっと、何か言ってよ。","ENG":"Well, say something.","TWN":"哥你也說幾句話吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"……싫어. 내가 애들 싫어하는 거 알잖아.","JPN":"……嫌だね。俺が子ども嫌いなの、知っているだろ？","ENG":"No. You know I hate talking to kids.","TWN":"……不要，你也知道我討厭小孩！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"그런 인간이 장난감 회사는 왜 갖겠다고 설쳤어?","JPN":"そんな奴がなんでオモチャ会社をあんなに欲しがったわけ？","ENG":"Then why did you go on that rant about running the toy company?!","TWN":"那你幹嘛還吵著要經營玩具公司？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"아, 맞다.","JPN":"あ、そうだ。","ENG":"Oh, right.","TWN":"對了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 혹시 체스 둘 줄 아니?","JPN":"ユイちゃん、もしかしてチェスとかできる？","ENG":"Jia, do you know how to play chess?","TWN":"小佳，你會下西洋棋嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"……체스요? 체스가 뭔가요?","JPN":"……チェス？　チェスって何ですか？","ENG":"Chess? What is it?","TWN":"……西洋棋？那是什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"이제는 애까지 도박판으로 끌어들이려고 그러냐. 나쁜 버릇 들이지 마.","JPN":"今度は子どもまで博打に付き合わせる気か。悪い癖をつけるなよ。","ENG":"You’re going to drag her into your mess now? Don’t turn her into an addict like you, okay?","TWN":"你現在是想讓她從小就學會賭博嗎？不要教她這種不良嗜好！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"오빠는 좀 빠져 있어.","JPN":"あのさ、割り込まないでくれる？","ENG":"Get lost, will you?","TWN":"哥你閉嘴啦！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 고모는 체스로 세계에서 세 손가락 안에 드는 실력자란다.","JPN":"ユイちゃん、私はチェスの世界で三本の指に入る実力者なのよ。","ENG":"Well, Jia. Auntie here is one of the top three chess players in the world.","TWN":"小佳，姑姑很會下西洋棋，是世界前三名喔～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"고모한테 배우면 지아도 강한 플레이어가 될 수 있을 거야.","JPN":"私に教われば、ユイちゃんもきっと強いプレイヤーになれるわよ。","ENG":"If you learn from me, I’m sure you’ll be a great player.","TWN":"姑姑可以教你，你就會成為很厲害的西洋棋高手。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"정말요? 어떻게 하는 건데요?","JPN":"本当に？　どうやるのですか？","ENG":"Really? How do I play?","TWN":"真的嗎？西洋棋要怎麼玩？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"그래, 우선 말 놓는 법부터 배워 보자. 지아는 흰색 말을 가지면 돼.","JPN":"よし、まずは駒の並べ方から覚えようか。ユイちゃんは白い駒を持ってね。","ENG":"Good girl. First, let’s learn how to place the pieces. Here Jia. You take the white ones.","TWN":"很好，那我們先來認識一下棋子，小佳你是白色的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"자, 폰은 이렇게 한 칸, 룩은 직진, 비숍은 대각선…….","JPN":"さあ、ポーンはこうやって1マス、ルークは直進、ビショップは斜め方向……","ENG":"Now, pawns can move forward one space at a time. Rooks can go straight, and bishops can move diagonally...","TWN":"兵前進一格，城堡要直走，主教要走斜線……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_FOOT_STEP"},{"id":"L1_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"폰은 한 칸……. 룩은 직진……. 비숍은 대각선…….","JPN":"ポーンは1マス、ルークは直進、ビショップは斜め方向……","ENG":"Pawns move forward one space... Rooks go straight... Bishops go diagonally...","TWN":"兵走一格……城堡直走……主教走斜線……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_CHILD_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_FOOT_STEP"},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"체스는 이 왕을 잡으면 이기는 게임이야. 그렇지만 왕은 약해서 지켜 줘야 해.","JPN":"チェスはこのキングをとれば勝利するゲームなの。\\nだけど、キングは弱いからみんなで守らないといけないの。","ENG":"The objective in chess is to capture the king. But the king is weak, so you have to protect it.","TWN":"西洋棋是先吃掉對方國王一方獲勝，而且國王很弱，需要保護他。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그 대신 이 여왕님은 다른 말들보다 뭐든 잘하거든. 여왕님이 있으니까 왕은 강할 필요가 없어.","JPN":"その代わり、このクイーンは他の駒よりなんでも上手。\\nクイーンがいるからキングは強くなる必要がないのよ。","ENG":"However, the queen is the strongest piece. Since the queen is so powerful, the king doesn’t have to be.","TWN":"而皇后是裡面最強的，只有要有皇后，國王不強也無所謂。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"……어?","JPN":"……あれっ？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"ALPHA_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"제가…… 이긴 거 맞나요?","JPN":"私が……勝ったのでしょうか？","ENG":"Did I... win?","TWN":"這樣……是算我贏嗎？"},"stage":{"bg":"ALPHA_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"와아……. 체스는 정말 쉽고 재밌는 거 같아요.","JPN":"わあ……チェスって本当に簡単で楽しいですね。","ENG":"Wow... Chess is really easy and fun!","TWN":"哇……西洋棋真的很簡單又好玩呢～"},"stage":{"bg":"ALPHA_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"너…… 너 어떻게 한 거야?","JPN":"あんた……どうやって……？","ENG":"H-how... did you do that?","TWN":"你……你是怎麼下的？"},"stage":{"bg":"ALPHA_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"네? 고모님이 가르쳐 주신 대로만 둔 건데요?","JPN":"はい？　叔母様に教わったとおりに動かしただけですよ？","ENG":"Hmm? I just play how you taught me to.","TWN":"嗯？我只是照姑姑教的去下而已？"},"stage":{"bg":"ALPHA_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"폰은 한 칸~ 룩은 직진~ 비숍은…….","JPN":"ポーンは1マスで、ルークは直進、ビショップは……","ENG":"Pawns move forward one space! Rooks go straight! Bishops move diagonally!","TWN":"兵走一格～城堡直走～主教……"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"장난치지 마! 말 놓는 법도 모르는 초짜가 날 이긴다고? 그것도 세 번이나?!","JPN":"ふざけないで！　駒の並べ方すら知らない初心者が私に勝つ？　しかも3回も！？","ENG":"Don’t lie to me! A beginner like you beating me?! And three times in a row?!","TWN":"開什麼玩笑！一個連棋要怎麼下都不知道的新手，怎麼可能贏過我？而且還贏我3次？！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_07"},{"id":"L15_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"당장 다시 둬! 빨리 말 잡아!!","JPN":"やり直しよ！　早く駒をとって！　今度は絶対に手加減しないからね！！","ENG":"Again! Reset the pieces! I’m not going easy on you this time!!","TWN":"再來一局！趕快開始！這次我不會再放水的！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"이번에는 절대 안 봐 줄 테니까!!","JPN":"今度は絶対に手加減しないからね！！","ENG":"I’m not going easy on you this time!!","TWN":"這次我不會再放水的！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그만해. 어린애 상대로 뭐 그리 호들갑이야.","JPN":"やめとけ。子ども相手に熱くなってどうするんだ。","ENG":"Enough. Why are you getting mad at the kid for?","TWN":"好了啦，你跟一個孩子是在計較什麼！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"기보도 읽을 줄 모르는 인간은 빠져 있어!! 이건 중요한 문제라고!!","JPN":"棋譜も読めない奴は黙ってて！！　これは大問題なんだから！！","ENG":"Hey! Back off if you don’t even know the rules of the game! This is important to me!!","TWN":"一個連棋譜都看不懂的人插什麼嘴！！這是很嚴重的問題！！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"어……. 그렇지만 고모님, 다시 해도 제가 이길 거예요.","JPN":"あ……でも、叔母様、もう一度やっても私が勝つと思いますよ。","ENG":"Um... But Auntie, I’m going to win even if we play again.","TWN":"嗯……姑姑，可是就算再下一局，贏的也是我。"},"stage":{"bg":"ALPHA_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"…What?","TWN":"……什麼？"},"stage":{"bg":"ALPHA_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"고모님은 기물 하나하나를 소중하게 안 다루시니까요. 그러면 왕을 지켜 줄 수가 없어요","JPN":"叔母様は一駒一駒を大切に扱わないからです。それでは、キングを守ることはできません。","ENG":"You see, you don’t treat your pieces with respect. And that’s why you can’t protect the king.","TWN":"因為姑姑在下棋時沒有步步為營，這樣就無法保護國王。"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"너, 나한테 어떻게 함부로 그딴 소리를……!","JPN":"あんた、よくもそんな生意気な口をきいて……！","ENG":"Y-you dare teach ME about chess?!","TWN":"你…你竟敢反過來對我說教……！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"한 번만 다시 하자, 지아야. 방금 전에는 내가 실력 발휘를 못한 거야.","JPN":"もう一回だけやろう、ユイちゃん。\\nさっきまでは実力を十分に発揮できなかっただけ。","ENG":"Let’s play another game, Jia. I must’ve underestimated you.","TWN":"再來一局！剛剛是我沒有發揮實力！"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"그래, 맞아. 어떻게 이런 꼬마한테…….","JPN":"そうよ、そうに違いないわ。じゃないと、私がこんなチビ相手に……","ENG":"Yeah... That’s it. There’s no way I could lose to this kid...","TWN":"沒錯！我怎麼可能輸給一個小鬼……"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"잠깐, 너 손목에 그거 뭐야?","JPN":"おい、手首のそれは何だ？","ENG":"Wait. What’s that on your wrist?","TWN":"等等，你手腕上那是什麼？"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 손목에?","JPN":"うん？　手首？","ENG":"Hmm? My wrist?","TWN":"什麼東西？手腕？"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L28_1","type":"dialog","speaker":"JIA_CHILD_ALPHA_NULL","text":{"KOREA":"아, 맞아요. 아까는 없었는데 체스 두는 내내 차고 계셨어요.","JPN":"あ、そうです。さっきまでは無かったのに、チェスゲームの間はずっと着けていたんです。","ENG":"Oh, he’s right. It wasn’t there before, but you were wearing it the whole time we were playing.","TWN":"喔，這個嗎？剛剛原本沒有的，下棋的時候突然跑出來。"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"It’s a...","TWN":"這是……"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WOMAN_NPC_ALPHA_NULL","text":{"KOREA":"<color=#ffd34c>시계</color>……?","JPN":"<color=#ffd34c>時計</color>……？","ENG":"<color=#ffd34c>Watch</color>...?","TWN":"<color=#ffd34c>能量環</color>……？"},"stage":{"bg":"ALPHA_04_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};